#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 10000
#define MAX_M 50000
struct Edge {
    int a, b, v;
};
int compare(const void *a, const void *b) {
    struct Edge *e1 = (struct Edge *)a;
    struct Edge *e2 = (struct Edge *)b;
    return e2->v - e1->v;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        struct Edge edges[M];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &edges[i].a, &edges[i].b, &edges[i].v);
        }
        qsort(edges, M, sizeof(struct Edge), compare);
        int backup[N + 1];
        memset(backup, -1, sizeof(backup));
        int quality = 0;
        for (int i = 0; i < M; i++) {
            if (backup[edges[i].a] == -1 && backup[edges[i].b] == -1) {
                backup[edges[i].a] = edges[i].b;
                backup[edges[i].b] = edges[i].a;
                quality += edges[i].v;
            }
        }
        if (quality == 0) {
            printf("impossible\n");
        } else {
            printf("%d\n", quality);
        }
    }
    return 0;
}

