// COMPLETE, COMPILABLE Java code
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class Edge implements Comparable<Edge> {
        int a, b, v;
        public Edge(int a, int b, int v) {
            this.a = a;
            this.b = b;
            this.v = v;
        }
        @Override
        public int compareTo(Edge o) {
            return o.v - v;
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            Edge[] edges = new Edge[M];
            for (int i = 0; i < M; i++) {
                edges[i] = new Edge(sc.nextInt(), sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(edges);
            int[] backup = new int[N + 1];
            Arrays.fill(backup, -1);
            int quality = 0;
            for (int i = 0; i < M; i++) {
                if (backup[edges[i].a] == -1 && backup[edges[i].b] == -1) {
                    backup[edges[i].a] = edges[i].b;
                    backup[edges[i].b] = edges[i].a;
                    quality += edges[i].v;
                }
            }
            if (quality == 0) {
                System.out.println("impossible");
            } else {
                System.out.println(quality);
            }
        }
    }
}

